import React, { useEffect, useState } from 'react';
import { useNavigate, useParams, Link } from 'react-router-dom';
import { createAlbum, getAlbum, updateAlbum, createAlbumWithImage, updateAlbumWithImage } from '../api/albumService';
import { getArtistes } from '../api/artisteService';

export default function AlbumForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [model, setModel] = useState({ titre: '', artisteId: '', image: null });
  const [artistes, setArtistes] = useState([]);
  const [existingImage, setExistingImage] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    getArtistes().then((response) => setArtistes(response.data || [])).catch(() => setArtistes([]));
  }, []);

  useEffect(() => {
    if (id) {
      setLoading(true);
      getAlbum(id)
        .then((response) => {
          const album = response.data || {};
          setModel({
            titre: album.titre || '',
            artisteId: album.artisteId || '',
            image: null,
          });
          setExistingImage(album.image || '');
        })
        .finally(() => setLoading(false));
    }
  }, [id]);

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);

    if (model.image) {
      const formData = new FormData();
      formData.append('titre', model.titre);
      formData.append('artisteId', model.artisteId);
      formData.append('image', model.image);
      const op = id ? updateAlbumWithImage(id, formData) : createAlbumWithImage(formData);
      op.then(() => navigate('/albums')).finally(() => setLoading(false));
      return;
    }

    const payload = {
      titre: model.titre,
      artisteId: parseInt(model.artisteId, 10) || null,
      image: existingImage || null,
    };

    const op = id ? updateAlbum(id, payload) : createAlbum(payload);
    op.then(() => navigate('/albums')).finally(() => setLoading(false));
  };

  return (
    <div>
      <div className="d-flex align-items-center justify-content-between mb-4">
        <div>
          <h1 className="h3 mb-0">{id ? 'Modifier' : 'Créer'} un album</h1>
          <p className="text-muted mb-0">Ajoutez un titre, sélectionnez un artiste et téléchargez une image.</p>
        </div>
        <Link className="btn btn-secondary" to="/albums">
          Retour aux albums
        </Link>
      </div>

      <form onSubmit={handleSubmit} className="card shadow-sm border-0 p-4">
        <div className="mb-3">
          <label className="form-label">Titre</label>
          <input
            className="form-control"
            value={model.titre}
            onChange={(e) => setModel({ ...model, titre: e.target.value })}
            required
          />
        </div>

        <div className="mb-3">
          <label className="form-label">Artiste</label>
          <select
            className="form-select"
            value={model.artisteId}
            onChange={(e) => setModel({ ...model, artisteId: e.target.value })}
            required
          >
            <option value="">Sélectionnez un artiste</option>
            {artistes.map((artiste) => (
              <option key={artiste.id} value={artiste.id}>
                {artiste.nom}
              </option>
            ))}
          </select>
        </div>

        {existingImage && (
          <div className="mb-3">
            <label className="form-label">Image actuelle</label>
            <div>
              <img
                src={`/uploads/images/${existingImage}`}
                alt={model.titre}
                className="img-thumbnail"
                style={{ maxWidth: 180 }}
              />
            </div>
          </div>
        )}

        <div className="mb-3">
          <label className="form-label">Image de couvercle</label>
          <input
            type="file"
            accept="image/*"
            className="form-control"
            onChange={(e) => setModel({ ...model, image: e.target.files[0] })}
          />
          <div className="form-text">Laisser vide pour garder l'image existante.</div>
        </div>

        <button className="btn btn-primary" type="submit" disabled={loading}>
          {loading ? 'Enregistrement...' : 'Sauvegarder'}
        </button>
      </form>
    </div>
  );
}
